                        {renderMediaContent(assets[0], "w-full h-auto max-h-[65vh] object-cover block")}
                    </div>

                    {/* Actual Visible Asset (Absolute Overlay) */}
                    <div className="absolute inset-0 w-full h-full">
                        {renderMediaContent(assets[currentSlide], "w-full h-full object-cover block")}
                    </div>

