                    {hasMultiple && currentSlide > 0 && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); navigate(-1); }}
                            className="absolute left-2 top-1/2 -translate-y-1/2 w-7 h-7 bg-white/90 rounded-full flex items-center justify-center shadow-md text-gray-800 hover:bg-white opacity-0 group-hover:opacity-100 transition-opacity z-20"
                        >
                            <ChevronLeft size={16} strokeWidth={3} />
                        </button>
                    )}
                    {hasMultiple && currentSlide < assets.length - 1 && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); navigate(1); }}
                            className="absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 bg-white/90 rounded-full flex items-center justify-center shadow-md text-gray-800 hover:bg-white opacity-0 group-hover:opacity-100 transition-opacity z-20"
                        >
                            <ChevronRight size={16} strokeWidth={3} />
                        </button>
                    )}
                </>
            ) : (
                // Empty State Fallback (Square)
                <div className="w-full aspect-square flex flex-col items-center justify-center text-gray-400">
                    <span className="text-[12px] font-medium">No Final Assets</span>
                </div>
            )}
        </div>

        {/* 3. Action Bar */}
        <div className="px-4 py-3 flex items-center justify-between shrink-0">
            <div className="flex items-center gap-4">
                <button onClick={() => setIsLiked(!isLiked)} className="hover:opacity-60 transition-opacity">
                    <Heart size={24} className={isLiked ? "fill-red-500 text-red-500" : "text-[#262626]"} strokeWidth={isLiked ? 0 : 2} />
                </button>
                <button className="hover:opacity-60 transition-opacity">
                    <MessageCircle size={24} className="text-[#262626] -rotate-90" />
                </button>
                <button className="hover:opacity-60 transition-opacity">
                    <Send size={24} className="text-[#262626] rotate-12 mb-1" />
                </button>
            </div>

            {/* Carousel Dots */}
            {hasMultiple && (
                <div className="flex gap-1.5">
                    {assets.map((_, idx) => (
                        <div 
                            key={idx} 
                            className={`w-1.5 h-1.5 rounded-full transition-colors ${idx === currentSlide ? 'bg-[#0095F6]' : 'bg-gray-300'}`} 
                        />
                    ))}
                </div>
            )}

            <button onClick={() => setIsSaved(!isSaved)} className="hover:opacity-60 transition-opacity">
                <Bookmark size={24} className={isSaved ? "fill-black text-black" : "text-[#262626]"} />
            </button>
        </div>

        {/* 4. Details Scroll Area */}
        <div className="flex-1 overflow-y-auto px-4 pb-2 text-[14px] text-[#262626]">

            {/* Likes */}
            <div className="font-semibold mb-2 text-[13px]">
