import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateMarketingStrategy = async (
  topic: string, 
  audience: string, 
  tone: string
): Promise<string> => {
  try {
    const prompt = `
      Act as a world-class creative director. 
      I need 5 distinct marketing hooks/angles for the following context:
      Topic/Product: ${topic}
      Target Audience: ${audience}
      Tone: ${tone}

      Format the output as a clean HTML list (<ul><li>...</li></ul>) without markdown backticks. 
      Keep each hook punchy and under 20 words.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Failed to generate strategy. Please try again.";
  }
};

export const generateHashtags = async (
  description: string,
  platform: string,
  tone: string
): Promise<{ broad: string[], niche: string[], brand: string[] }> => {
  try {
    const prompt = `
      Generate a set of optimized hashtags for a ${platform} post.

      CONTEXT:
      Description/Caption: "${description}"
      Tone: ${tone}

      RULES:
      1. Provide exactly 30 hashtags total.
      2. Group them into 3 categories:
         - 'broad': High volume, general reach tags (approx 10).
         - 'niche': Specific, targeted community tags (approx 10).
         - 'brand': Unique, branded, or very specific lifestyle tags (approx 10).
      3. Return ONLY a valid JSON object with keys "broad", "niche", and "brand". Each key should contain an array of strings.
      4. Do not include the '#' symbol in the strings, I will add it later.
      5. Ensure tags are relevant and professional.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            broad: { type: Type.ARRAY, items: { type: Type.STRING } },
            niche: { type: Type.ARRAY, items: { type: Type.STRING } },
            brand: { type: Type.ARRAY, items: { type: Type.STRING } },
          }
        }
      }
    });

    const jsonStr = response.text;
    if (!jsonStr) throw new Error("Empty response");

    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Gemini Hashtag Error:", error);
    return { broad: [], niche: [], brand: [] };
  }
};

