export const HashtagGenCard: React.FC<HashtagGenCardProps> = (props) => {
  const { card, allCards, onUpdateContent } = props;
  const content = card.content as HashtagGenContent;

  const [isGenerating, setIsGenerating] = useState(false);
  const [showLinkMenu, setShowLinkMenu] = useState(false);

  // Initialize
  useEffect(() => {
    if (!content.tags) {
      onUpdateContent(card.id, {
        title: 'Hashtag Generator',
        inputText: '',
        platform: 'instagram',
        tone: 'Casual',
        tags: [],
        linkedPostId: undefined
      });
    }
  }, []);

  // Sync Logic: If linked, update inputText when the linked post changes?
  // Or simpler: When card mounts or linkedId changes, pull the caption.
  useEffect(() => {
    if (content.linkedPostId) {
        const post = allCards.find(c => c.id === content.linkedPostId);
        if (post && post.content.caption && post.content.caption !== content.inputText) {
            // Only auto-fill if input is empty or strictly matches previous sync to avoid overwriting user edits
            // For MVP, let's just pull it once when linking or manually refreshing? 
            // Better UX: If connected, the input acts as a "live view" or at least a "fetchable" view.
            // Let's implement a manual "Pull Caption" or auto-pull on link.
        }
    }
  }, [content.linkedPostId, allCards]);

  const handleLinkPost = (postId: string) => {
      const post = allCards.find(c => c.id === postId);
      if (post) {
          onUpdateContent(card.id, { 
              ...content, 
              linkedPostId: postId,
              inputText: (post.content as PostCardContent).caption || content.inputText
          });
          setShowLinkMenu(false);
          soundService.play('snap');
      }
  };

  const handleUnlink = () => {
      onUpdateContent(card.id, { ...content, linkedPostId: undefined });
  };

  const handleGenerate = async () => {
      if (!content.inputText.trim()) return;

      setIsGenerating(true);
      const result = await generateHashtags(content.inputText, content.platform, content.tone);

      const newTags: HashtagItem[] = [];
      const process = (list: string[], cat: 'broad' | 'niche' | 'brand') => {
          list.forEach(tag => newTags.push({
              id: `${cat}-${tag}-${Date.now()}`,
              tag: tag.replace('#', ''), // clean raw output
              category: cat,
              selected: true // Select all by default
          }));
      };

      process(result.broad, 'broad');
      process(result.niche, 'niche');
      process(result.brand, 'brand');

      onUpdateContent(card.id, { ...content, tags: newTags });
      setIsGenerating(false);
      soundService.play('success');
  };

  const toggleTag = (id: string) => {
      const newTags = content.tags.map(t => t.id === id ? { ...t, selected: !t.selected } : t);
      onUpdateContent(card.id, { ...content, tags: newTags });
  };

  const copyTags = () => {
      const selected = content.tags.filter(t => t.selected).map(t => `#${t.tag}`).join(' ');
      if (selected) {
          navigator.clipboard.writeText(selected);
          soundService.play('toggle'); // reused for feedback
      }
  };

  const insertIntoPost = () => {
      if (!content.linkedPostId) return;
      const post = allCards.find(c => c.id === content.linkedPostId);
      if (!post) return;

      const selected = content.tags.filter(t => t.selected).map(t => `#${t.tag}`).join(' ');
      if (!selected) return;

      const currentCaption = (post.content as PostCardContent).caption || "";
      const newCaption = currentCaption ? `${currentCaption}\n\n${selected}` : selected;

      // Update the Linked Post Card
      onUpdateContent(content.linkedPostId, { ...post.content, caption: newCaption });
      soundService.play('snap');
  };

  const selectedCount = content.tags?.filter(t => t.selected).length || 0;
  const linkedPost = allCards.find(c => c.id === content.linkedPostId);

  // Filter available posts for linking
  const availablePosts = allCards.filter(c => c.type === 'POST' || c.type === 'IMAGE' || c.type === 'LINK');

  return (
    <BaseCard 
      {...props} 
      title={content.title || "Hashtag Generator"} 
      icon={<Hash size={16} className="text-[#3A5C34]" />}
    >
      <div className="flex flex-col h-full bg-[#F9F8F6]">

        {/* --- 1. CONTEXT HEADER --- */}
        <div className="px-4 py-3 bg-white border-b border-gray-100 flex items-center justify-between shrink-0">
            {linkedPost ? (
                <div className="flex items-center gap-2 bg-[#3A5C34]/10 text-[#3A5C34] px-2 py-1 rounded-lg text-[11px] font-bold max-w-[80%]">
                    <LinkIcon size={12} />
                    <span className="truncate">{linkedPost.content.title || "Linked Post"}</span>
                    <button onClick={handleUnlink} className="hover:text-red-500 transition-colors ml-1"><X size={12}/></button>
                </div>
            ) : (
                <div className="relative">
                    <button 
                        onClick={() => setShowLinkMenu(!showLinkMenu)}
                        className="flex items-center gap-1.5 text-[11px] font-bold text-gray-400 hover:text-[#3A5C34] transition-colors"
                    >
                        <LinkIcon size={12} /> Link to Post
                    </button>

                    {/* Link Dropdown */}
                    {showLinkMenu && (
                        <div className="absolute top-full left-0 mt-2 w-64 bg-white rounded-xl shadow-xl border border-gray-100 z-50 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                            <div className="px-3 py-2 text-[10px] font-bold text-gray-400 uppercase bg-gray-50">Select a Post</div>
                            <div className="max-h-48 overflow-y-auto">
                                {availablePosts.map(p => (
                                    <button
                                        key={p.id}
                                        onClick={() => handleLinkPost(p.id)}
                                        className="w-full text-left px-3 py-2 text-[12px] hover:bg-gray-50 truncate border-b border-gray-50 last:border-0"
                                    >
                                        {p.content.title || "Untitled Post"}
                                    </button>
                                ))}
                                {availablePosts.length === 0 && (
                                    <div className="px-3 py-4 text-center text-gray-400 text-[11px]">No posts found</div>
                                )}
                            </div>
                        </div>
                    )}
                </div>
            )}

            <div className="flex gap-1">
                {PLATFORMS.map(p => (
                    <button
                        key={p.id}
                        onClick={() => onUpdateContent(card.id, { ...content, platform: p.id })}
                        className={`w-6 h-6 rounded-md flex items-center justify-center transition-all ${content.platform === p.id ? `${p.bg} ${p.color} ring-1 ring-inset ring-current` : 'text-gray-300 hover:text-gray-500'}`}
                    >
                        {p.icon}
                    </button>
                ))}
            </div>
        </div>

        {/* --- 2. INPUT AREA --- */}
        <div className="p-4 bg-white space-y-3 shrink-0">
            <textarea 
                value={content.inputText}
                onChange={(e) => onUpdateContent(card.id, { ...content, inputText: e.target.value })}
                placeholder="Describe your post, audience, and key themes..."
                className="w-full h-20 bg-[#F9FAFB] rounded-xl border-none text-[13px] leading-relaxed p-3 focus:ring-1 focus:ring-[#3A5C34] resize-none placeholder-gray-400"
            />

            <div className="flex items-center justify-between">
                <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar max-w-[60%]">
                    {TONES.map(t => (
                        <button 
                            key={t}
                            onClick={() => onUpdateContent(card.id, { ...content, tone: t })}
                            className={`px-2.5 py-1 rounded-full text-[10px] font-bold border transition-all whitespace-nowrap
                                ${content.tone === t ? 'bg-[#3A5C34] text-white border-[#3A5C34]' : 'bg-white text-gray-500 border-gray-200 hover:border-gray-300'}
                            `}
                        >
                            {t}
                        </button>
                    ))}
                </div>
                <button 
                    onClick={handleGenerate}
                    disabled={isGenerating || !content.inputText}
                    className="flex items-center gap-2 px-4 py-1.5 bg-[#3A5C34] text-white rounded-full text-[12px] font-bold shadow-sm hover:bg-[#2d4a29] active:scale-95 disabled:opacity-50 transition-all"
                >
                    {isGenerating ? <RefreshCw size={14} className="animate-spin"/> : <Wand2 size={14} />}
                    Generate
                </button>
            </div>
        </div>

        {/* --- 3. RESULTS AREA --- */}
        <div className="flex-1 overflow-y-auto p-4 space-y-5 min-h-0">
            {content.tags && content.tags.length > 0 ? (
                <>
                    {['broad', 'niche', 'brand'].map(cat => {
                        const tags = content.tags.filter(t => t.category === cat);
                        if (tags.length === 0) return null;

                        // Theme colors for categories
                        const theme = cat === 'broad' ? 'blue' : (cat === 'niche' ? 'purple' : 'emerald');
                        const label = cat === 'broad' ? 'High Reach' : (cat === 'niche' ? 'Targeted' : 'Brand Specific');

                        return (
                            <div key={cat} className="space-y-2">
                                <div className={`text-[10px] font-bold uppercase tracking-wider text-${theme}-600 ml-1`}>
                                    {label}
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    {tags.map(tag => (
                                        <button
                                            key={tag.id}
                                            onClick={() => toggleTag(tag.id)}
                                            className={`
                                                px-3 py-1.5 rounded-lg text-[12px] font-medium transition-all border
                                                ${tag.selected 
                                                    ? 'bg-white border-gray-300 text-gray-900 shadow-sm ring-1 ring-gray-200' 
                                                    : 'bg-transparent border-transparent text-gray-400 hover:bg-gray-100 hover:text-gray-600'
                                                }
                                            `}
                                        >
                                            <span className="opacity-50 mr-0.5">#</span>{tag.tag}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </>
            ) : (
                <div className="h-full flex flex-col items-center justify-center text-gray-300 space-y-3 pb-8">
                    <div className="w-16 h-16 rounded-full bg-gray-100 flex items-center justify-center">
                        <Sparkles size={24} className="text-gray-300" />
                    </div>
                    <p className="text-[12px] font-medium">Ready to generate ideas</p>
