                            className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/5 disabled:opacity-30 disabled:hover:bg-transparent transition-colors border-r border-[#5F2427]/5"
                        >
                            <Undo2 size={16} strokeWidth={2.5} />
                        </button>
                        {/* Redo */}
                        <button 
                            onClick={handleRedo} 
                            disabled={future.length === 0} 
                            className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/5 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        >
                            <Redo2 size={16} strokeWidth={2.5} />
                        </button>
                    </div>

                    {/* 3. Exit Button (Panic Button Style: Pink BG, Burgundy Icon) */}
                    <button 
                        onClick={handleExitWhiteboard}
                        className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"
                        title="Exit Whiteboard"
                    >
                        <LogOut size={18} strokeWidth={2.5} className="ml-0.5" />
                    </button>
                </div>

                {/* Tools Drawer Button (Visual indicator for the hover zone) */}
                <div className="absolute top-6 left-6 z-40">
                    <button onClick={() => setIsDrawerOpen(true)} className="w-12 h-12 rounded-full bg-[#3A5C34] shadow-lg border border-white/20 flex items-center justify-center text-white hover:scale-110 transition-all">
                       <Plus size={24} strokeWidth={1.5} />
                    </button>
                </div>

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}

                {/* Tab Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        {/* Renaming Input Removed from Popover - Inline Editing Preferred */}
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}
            </div>
         ) : (
            /* --- VIEW: PAGE / FOLDER DASHBOARD --- */
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={handleToggleFavorite}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
            />
         )}
      </div>

    </div>
  );
}

  // Default Content for Text/Sticky (Mirrored from Canvas Mouse Down logic)
  if (type === CardType.TEXT) {
     newCard.content = { text: 'Type something...', fontSize: 24, fontFamily: 'Inter', textAlign: 'left', color: '#1C1C1E' };
  }
  if (type === CardType.STICKY) {
     newCard.content = { text: '', color: '#FFF475', fontSize: 24, shape: 'square' };
  }
  if (type === CardType.HASHTAG_GEN) {
     newCard.content = {
        title: 'Hashtag Generator',
        inputText: '',
        platform: 'instagram',
        tone: 'Casual',
        tags: [],
        linkedPostId: undefined
     };
  }

  updateCards([...activeWorkspace.cards, newCard]);
  // Don't close drawer immediately for continuous adding
};

{/* --- 2. INPUT AREA --- */}
<div className="p-4 bg-white space-y-3 shrink-0">
    <textarea 
        value={content.inputText || ''}
        onChange={(e) => onUpdateContent(card.id, { ...content, inputText: e.target.value })}
        placeholder="Describe your post, audience, and key themes..."
        className="w-full h-20 bg-[#F9FAFB] rounded-xl border-none text-[13px] leading-relaxed p-3 focus:ring-1 focus:ring-[#3A5C34] resize-none placeholder-gray-400"
    />

    <div className="flex items-center justify-between">
        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar max-w-[60%]">
            {TONES.map(t => (
                <button 
                    key={t}
                    onClick={() => onUpdateContent(card.id, { ...content, tone: t })}
                    className={`px-2.5 py-1 rounded-full text-[10px] font-bold border transition-all whitespace-nowrap
                        ${content.tone === t ? 'bg-[#3A5C34] text-white border-[#3A5C34]' : 'bg-white text-gray-500 border-gray-200 hover:border-gray-300'}
                    `}
                >
                    {t}
                </button>
            ))}
