</div>

import React, { useState } from 'react';
import { Canvas } from './components/Canvas';
import { Sidebar } from './components/Sidebar';
import { ToolsDock } from './components/ui/ToolsDock';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { PageView } from './components/PageView';
import { 
  CardData, ToolType, Position, FileSystemNode, NodeType 
} from './types';

// Mock Initial Data
const INITIAL_NODES: Record<string, FileSystemNode> = {
  'root': { id: 'root', type: 'folder', name: 'Home', parentId: null, children: ['folder-1'] },
  'folder-1': { id: 'folder-1', type: 'folder', name: 'Campaigns', parentId: 'root', children: ['wb-1'] },
  'wb-1': { 
    id: 'wb-1', 
    type: 'whiteboard', 
    name: 'Q1 Strategy', 
    parentId: 'folder-1', 
    whiteboardData: [{ id: 'ws-1', name: 'Main', cards: [] }] 
  }
};

const App: React.FC = () => {
  // --- STATE ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>(INITIAL_NODES);
  const [activeNodeId, setActiveNodeId] = useState<string>('root');

  // Canvas State (derived from active node if it's a whiteboard)
  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });

  // History for Undo/Redo (Simplified)
  const [history, setHistory] = useState<CardData[][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // --- ACTIONS ---

  const handleNavigate = (id: string) => {
    setActiveNodeId(id);
    // Reset Canvas State on navigation
    setScale(1);
    setPan({ x: 0, y: 0 });
    setActiveTool('SELECT');
    setHistory([]);
    setHistoryIndex(-1);
  };

  const updateNode = (id: string, updates: Partial<FileSystemNode>) => {
    setNodes(prev => ({
      ...prev,
      [id]: { ...prev[id], ...updates }
    }));
  };

  const handleCardsChange = (newCards: CardData[]) => {
    // 1. Update Node Data
    const node = nodes[activeNodeId];
    if (node && node.type === 'whiteboard' && node.whiteboardData) {
       const updatedWorkspaces = [...node.whiteboardData];
       if (updatedWorkspaces.length > 0) {
           updatedWorkspaces[0] = { ...updatedWorkspaces[0], cards: newCards };
           updateNode(activeNodeId, { whiteboardData: updatedWorkspaces });
       }
    }

    // 2. History
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(newCards);
    // Limit history size
    if (newHistory.length > 50) newHistory.shift();
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      const cards = history[newIndex];
      const node = nodes[activeNodeId];
      if (node && node.type === 'whiteboard' && node.whiteboardData) {
         const updatedWorkspaces = [...node.whiteboardData];
         if (updatedWorkspaces.length > 0) {
             updatedWorkspaces[0] = { ...updatedWorkspaces[0], cards };
             updateNode(activeNodeId, { whiteboardData: updatedWorkspaces });
         }
      }
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      const cards = history[newIndex];
      const node = nodes[activeNodeId];
      if (node && node.type === 'whiteboard' && node.whiteboardData) {
         const updatedWorkspaces = [...node.whiteboardData];
         if (updatedWorkspaces.length > 0) {
             updatedWorkspaces[0] = { ...updatedWorkspaces[0], cards };
             updateNode(activeNodeId, { whiteboardData: updatedWorkspaces });
         }
      }
    }
  };

  // --- FILE SYSTEM OPS ---

  const createNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    const newNode: FileSystemNode = {
      id,
      type,
      name: type === 'folder' ? 'New Folder' : 'New Whiteboard',
      parentId: parentId || (nodes[activeNodeId]?.type === 'folder' ? activeNodeId : 'root'),
      whiteboardData: type === 'whiteboard' ? [{ id: `ws-${Date.now()}`, name: 'Main', cards: [] }] : undefined
    };

    setNodes(prev => {
      const next = { ...prev, [id]: newNode };
      const pId = newNode.parentId;
      if (pId && next[pId]) {
         next[pId] = { 
           ...next[pId], 
           children: [...(next[pId].children || []), id] 
         };
      }
      return next;
    });

    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const deleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          Object.values(next).forEach(n => {
              if (n.children?.includes(id)) {
                  next[n.id] = { ...n, children: n.children.filter(c => c !== id) };
              }
          });
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const moveNode = (dragId: string, targetId: string) => {
      setNodes(prev => {
          const node = prev[dragId];
          const oldParentId = node.parentId;
          if (!node || !prev[targetId]) return prev;

          const next = { ...prev };

          if (oldParentId && next[oldParentId]) {
              next[oldParentId] = {
                  ...next[oldParentId],
                  children: next[oldParentId].children?.filter(c => c !== dragId)
              };
          }

          next[dragId] = { ...node, parentId: targetId };

          next[targetId] = {
              ...next[targetId],
              children: [...(next[targetId].children || []), dragId]
          };

          return next;
      });
  };

  // --- RENDER ---
  const activeNode = nodes[activeNodeId] || nodes['root'];
  const isWhiteboard = activeNode?.type === 'whiteboard';
  const activeCards = isWhiteboard && activeNode.whiteboardData && activeNode.whiteboardData.length > 0
    ? activeNode.whiteboardData[0].cards 
    : [];

  return (
    <div className="flex w-full h-screen bg-[#F9F8F6] text-[#1C1C1E] font-sans overflow-hidden">
      <Sidebar 
        nodes={nodes}
        activeNodeId={activeNodeId}
        onNavigate={handleNavigate}
        onToggleExpand={(id) => updateNode(id, { isExpanded: !nodes[id].isExpanded })}
        onCreateNode={createNode}
        onToggleFavorite={(id) => updateNode(id, { isFavorite: !nodes[id].isFavorite })}
        onMoveNode={moveNode}
        onUpdateNode={updateNode}
        onDeleteNode={deleteNode}
      />

      <div className="flex-1 relative h-full flex flex-col min-w-0">
        {isWhiteboard ? (
            <>
                <Canvas 
                    cards={activeCards}
                    onCardsChange={handleCardsChange}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                />

                <ToolsDock 
                    activeTool={activeTool}
                    onToolChange={setActiveTool}
                    canUndo={historyIndex > 0}
                    canRedo={historyIndex < history.length - 1}
                    onUndo={handleUndo}
                    onRedo={handleRedo}
                />

                {(['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool)) && (
                    <DrawingToolbar 
                        activeTool={activeTool}
                        onToolChange={setActiveTool}
                        onClose={() => setActiveTool('SELECT')}
                    />
                )}
            </>
        ) : (
            <PageView 
                node={activeNode}
                childNodes={Object.values(nodes).filter(n => n.parentId === activeNodeId)}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => createNode('whiteboard', activeNodeId)}
                onCreateFolder={() => createNode('folder', activeNodeId)}
                onUpdateNode={updateNode}
                onToggleFavorite={(id) => updateNode(id, { isFavorite: !nodes[id].isFavorite })}
                onReorderNode={moveNode}
            />
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, HashtagGenContent } from '../../types';
import { Hash, Copy, RefreshCw, Wand2, Check, Loader2 } from 'lucide-react';
import { generateHashtags } from '../../services/geminiService';

interface HashtagGenCardProps {
  card: CardData;
  allCards: CardData[];
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  onResize: (id: string, geometry: { width: number; height: number; x?: number; y?: number }) => void;
  zoomScale: number;
}

const TONES = ['Professional', 'Casual', 'Funny', 'Excited', 'Luxurious', 'Urgent'];

export const HashtagGenCard: React.FC<HashtagGenCardProps> = (props) => {
  const { card, onUpdateContent } = props;
  const content = card.content as HashtagGenContent;

  const [isGenerating, setIsGenerating] = useState(false);
  const [copiedGroup, setCopiedGroup] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!content.inputText) return;

    setIsGenerating(true);
    try {
        const result = await generateHashtags(content.inputText, content.platform, content.tone);

        const newTags = [
            ...result.broad.map(t => ({ id: Math.random().toString(), tag: t, category: 'broad' as const, selected: true })),
            ...result.niche.map(t => ({ id: Math.random().toString(), tag: t, category: 'niche' as const, selected: true })),
            ...result.brand.map(t => ({ id: Math.random().toString(), tag: t, category: 'brand' as const, selected: true })),
        ];

        onUpdateContent(card.id, { ...content, tags: newTags });
    } catch (e) {
        console.error(e);
    } finally {
        setIsGenerating(false);
    }
  };

  const copyToClipboard = (category?: string) => {
      const tagsToCopy = category 
        ? content.tags.filter(t => t.category === category && t.selected)
        : content.tags.filter(t => t.selected);

      const text = tagsToCopy.map(t => `#${t.tag}`).join(' ');
      navigator.clipboard.writeText(text);

      setCopiedGroup(category || 'all');
      setTimeout(() => setCopiedGroup(null), 2000);
  };

  const toggleTag = (id: string) => {
      const newTags = content.tags.map(t => t.id === id ? { ...t, selected: !t.selected } : t);
      onUpdateContent(card.id, { ...content, tags: newTags });
  };

  return (
    <BaseCard 
      {...props} 
      title="Hashtag Generator" 
      icon={<Hash size={16} className="text-[#3A5C34]"/>}
    >
      <div className="flex flex-col h-full bg-[#F9FAFB] divide-y divide-gray-100">

        {/* --- INPUT AREA --- */}
        <div className="p-4 bg-white space-y-3 shrink-0">
            <textarea 
                value={content.inputText || ''}
                onChange={(e) => onUpdateContent(card.id, { ...content, inputText: e.target.value })}
                placeholder="Describe your post, audience, and key themes..."
                className="w-full h-20 bg-[#F9FAFB] rounded-xl border-none text-[13px] leading-relaxed p-3 focus:ring-1 focus:ring-[#3A5C34] resize-none placeholder-gray-400"
            />

            <div className="flex items-center justify-between">
                <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar max-w-[60%]">
                    {TONES.map(t => (
                        <button 
                            key={t}
                            onClick={() => onUpdateContent(card.id, { ...content, tone: t })}
                            className={`px-2.5 py-1 rounded-full text-[10px] font-bold border transition-all whitespace-nowrap
                                ${content.tone === t ? 'bg-[#3A5C34] text-white border-[#3A5C34]' : 'bg-white text-gray-500 border-gray-200 hover:border-gray-300'}
                            `}
                        >
                            {t}
                        </button>
                    ))}
                </div>
                <button 
                    onClick={handleGenerate}
                    disabled={isGenerating || !content.inputText}
                    className="flex items-center gap-2 px-4 py-1.5 bg-[#3A5C34] text-white rounded-full text-[12px] font-bold shadow-sm hover:bg-[#2d4a29] active:scale-95 disabled:opacity-50 transition-all"
                >
                    {isGenerating ? <Loader2 size={14} className="animate-spin"/> : <Wand2 size={14} />}
                    Generate
                </button>
            </div>
        </div>

        {/* --- RESULTS AREA --- */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6">
            {!content.tags || content.tags.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-gray-400">
                    <Hash size={24} className="mb-2 opacity-20"/>
                    <span className="text-[12px]">Ready to generate</span>
                </div>
            ) : (
                <>
                   {['broad', 'niche', 'brand'].map(cat => {
                       const tags = content.tags.filter(t => t.category === cat);
                       if (tags.length === 0) return null;
                       return (
                           <div key={cat}>
                               <div className="flex items-center justify-between mb-2">
                                   <span className="text-[11px] font-bold uppercase text-gray-400 tracking-wider">{cat} Reach</span>
                                   <button 
                                      onClick={() => copyToClipboard(cat)}
                                      className="text-[10px] font-medium text-gray-400 hover:text-[#3A5C34] flex items-center gap-1"
                                   >
                                       {copiedGroup === cat ? <Check size={10} /> : <Copy size={10} />}
                                       {copiedGroup === cat ? 'Copied' : 'Copy Group'}
                                   </button>
                               </div>
                               <div className="flex flex-wrap gap-2">
                                   {tags.map(t => (
                                       <button
                                           key={t.id}
                                           onClick={() => toggleTag(t.id)}
                                           className={`px-2 py-1 rounded-md text-[12px] border transition-all
                                               ${t.selected ? 'bg-white border-gray-200 text-gray-700 shadow-sm' : 'bg-transparent border-transparent text-gray-300 line-through'}
                                           `}
                                       >
                                           #{t.tag}
                                       </button>
                                   ))}
                               </div>
                           </div>
                       );
                   })}
                </>
            )}
        </div>

        {/* --- FOOTER --- */}
        {content.tags && content.tags.length > 0 && (
            <div className="p-3 bg-white border-t border-gray-100 flex items-center justify-between">
                <span className="text-[11px] font-medium text-gray-400">
                    {content.tags.filter(t => t.selected).length} selected
                </span>
                <button 
                    onClick={() => copyToClipboard()}
                    className="flex items-center gap-1.5 text-[#3A5C34] text-[12px] font-bold hover:bg-[#3A5C34]/5 px-3 py-1.5 rounded-lg transition-colors"
                >
                    {copiedGroup === 'all' ? <Check size={14} /> : <Copy size={14} />}
                    {copiedGroup === 'all' ? 'Copied All' : 'Copy All'}
                </button>
            </div>
        )}

      </div>
    </BaseCard>
  );
};
